/**
 * @param {number} n
 * @param {number[][]} edges
 * @return {number}
 */
function solve(n, edges) {
    // We are dealing with the parity of cycle sums.
    // A key property of graph cycle parity is related to Bipartite Graphs.
    // In a graph where all edge weights are 0 or 1:
    // - If a graph is bipartite, all cycles must have an even sum (if we assign colors 0 and 1
    //   and define path weight as XOR sum of edge weights, this is equivalent to checking
    //   if the XOR sum of cycle edges is 0, which is even).
    // - If a graph is not bipartite, it contains at least one cycle with an odd sum.

    // The condition "the sum of edge weights in every cycle is even" is equivalent to
    // stating that the graph formed by the edges added so far is bipartite, when edge
    // weights are treated as parity (1 if weight is 1, 0 if weight is 0).

    // Since edge weights are 0 or 1, the sum parity is equivalent to the XOR sum.
    // A graph where all cycle XOR sums are 0 is equivalent to a bipartite graph
    // where edge weights correspond to the XOR difference between the partitions.

    // We can use Disjoint Set Union (DSU) structure augmented to track parity (relative distance).
    // For each node i, we store parent[i] and diff[i].
    // diff[i] stores the parity of the path weight from node i to its current root parent[i].
    // diff[i] = 0 means path weight is even.
    // diff[i] = 1 means path weight is odd.

    const parent = Array(n).fill(0).map((_, i) => i);
    // diff[i] = parity of the path weight from i to parent[i]
    const diff = Array(n).fill(0);

    /**
     * Finds the root of node i and updates diff[i] to reflect the parity
     * of the path from i to the ultimate root.
     * @param {number} i
     * @returns {number} The root of i.
     */
    function find(i) {
        if (parent[i] === i) {
            return i;
        }
        const root = find(parent[i]);
        // Path compression: update diff[i]
        // The new path from i to root is (i -> parent[i]) + (parent[i] -> root)
        // Parity addition is XOR.
        diff[i] = diff[i] ^ diff[parent[i]];
        parent[i] = root;
        return root;
    }

    /**
     * Unites the sets containing u and v, considering the edge weight w.
     * @param {number} u
     * @param {number} v
     * @param {number} w - The weight of the edge (0 or 1).
     * @returns {boolean} True if the edge was successfully added (no odd cycle created), false otherwise.
     */
    function unite(u, v, w) {
        const rootU = find(u);
        const rootV = find(v);

        if (rootU !== rootV) {
            // They are in different components. We merge them.
            // Let's merge rootV into rootU. parent[rootV] = rootU.
            parent[rootV] = rootU;

            // We need to set diff[rootV] such that the path parity from rootV to rootU
            // is consistent with the edge (u, v) and existing path parities.

            // Path from u to rootU: parity = diff[u]
            // Path from v to rootV: parity = diff[v]
            // Edge (u, v): parity = w

            // We want: Path(rootV -> v) + Edge(v -> u) + Path(u -> rootU) = 0 (modulo 2)
            // Path(rootV -> v) is diff[v] (reversed direction, parity stays same)
            // Edge(v -> u) is w
            // Path(u -> rootU) is diff[u]

            // We are setting parent[rootV] = rootU. We need diff[rootV], which is the parity of 
            // path (rootV -> rootU).

            // Path(rootV -> rootU) = Path(rootV -> v) + Edge(v -> u) + Path(u -> rootU)
            // Path(rootV -> v) = diff[v]
            // Edge(v -> u) = w
            // Path(u -> rootU) = diff[u]

            // Parity: diff[rootV] = diff[v] ^ w ^ diff[u]
            diff[rootV] = diff[v] ^ w ^ diff[u];
            return true;
        } else {
            // They are in the same component. Adding the edge (u, v) creates a cycle.
            // Cycle path parity: Path(u -> rootU) + Edge(u -> v) + Path(v -> rootV) (which is u->v)

            // Parity of cycle = diff[u] ^ w ^ diff[v]
            // If this parity is 1 (odd), the condition is violated.
            const cycleParity = diff[u] ^ w ^ diff[v];

            if (cycleParity === 0) {
                // Even cycle sum, add the edge.
                return true;
            } else {
                // Odd cycle sum, do not add the edge.
                return false;
            }
        }
    }

    let addedEdgesCount = 0;
    for (const [u, v, w] of edges) {
        // The unite function returns true if the edge is added, false otherwise.
        if (unite(u, v, w)) {
            addedEdgesCount++;
        }
    }

    return addedEdgesCount;
}

